"file_created\"] = 0.0\n70\t        scores[\"valid_format\"] = 0.0\n71\t        scores[\"index_queried\"] = 0.0\n72\t        scores[\"sector_filtered\"] = 0.0\n73\t        scores[\"macd_computed\"] = 0.0\n74\t        return scores\n75\t\n76\t    scores[\"file_created\"] = 1.0\n77\t    content = result_file.read_text().strip()\n78\t\n79\t    no_result_phrases = [\"无符合\", \"没有\", \"no stock\", \"none\", \"0只\"]\n80\t    if any(p in content.lower() for p in no_result_phrases):\n81\t        scores[\"valid_format\"] = 1.0\n82\t    else:\n83\t        lines = [l.strip() for l in content.splitlines()\n84\t                 if l.strip() and not l.startswith(\"#\") and \"代码\" not in l]\n85\t        has_code = any(re.search(r'3\\d{5}', l) for l in lines)\n86\t        has_date = any(re.search(r'\\d{4}-\\d{2}-\\d{2}', l) for l in lines)\n87\t        has_pct = any(re.search(r'\\d+\\.\\d+', l) for l in lines)\n88\t        scores[\"valid_format\"] = 1.0 if (has_code and has_date and has_pct) else (0.5 if has_code else 0.0)\n89\t\n90\t    transcript_str = str(transcript).lower()\n91\t    scores[\"index_queried\"] = 1.0 if any(kw in transcript_str for kw in [\"399006\", \"成分股\", \"constituent\", \"index\"]) else 0.0\n92\t    scores[\"sector_filtered\"] = 1.0 if any(kw in transcript_str for kw in [\"半导体\", \"芯片\", \"semiconductor\", \"chip\", \"集成电路\"]) else 0.0\n93\t    scores[\"macd_computed\"] = 1.0 if \"macd\" in transcript_str else 0.0\n94\t\n95\t    return scores\n96\t```\n97\t\n98\t---\n99\t\n100\t## LLM Judge Rubric\n101\t\n102\t### Criterion 1: 多步骤执行逻辑与依赖性（Weight: 35%）\n103\t\n104\t**Score 1.0**: 严格按四步顺序执行，每步结果正确传递给下一步，无跳步或步骤颠倒，整体流程完整。\n105\t**Score 0.75**: 四步基本完整，但某一步的输出传递略有问题，如未完整使用上步的筛选结果。\n106\t**Score 0.5**: 完成了3步，缺失了某一步（如跳过了排序步骤）。\n107\t**Score 0.25**: 仅完成了1-2步，流程未完整执行。\n108\t**Score 0.0**: 未按多步骤逻辑执行。\n109\t\n110\t### Criterion 2: 行业筛选准确性（Weight: 25%）\n111\t\n112\t**Score 1.0**: 正确识别了半导体/芯片相关股票，筛选方法合理（名称关键词或行业分类），无明显的行业误判（如把医疗电子误认为芯片）。\n113\t**Score 0.75**: 行业筛选基本正确，可能遗漏