sensus_batch/default_run/task_11_semiconductor_macd/revised/ga\\\"\\n\\nprint(\\\"=== 第一步：获取创业板股票列表 ===\\\")\\n# 获取A股实时行情数据\\nstock_df = ak.stock_zh_a_spot_em()\\n# 筛选创业板股票（300开头）\\ngem_stocks = stock_df[stock_df['代码'].str.startswith('300')].copy()\\nprint(f\\\"创业板股票总数: {len(gem_stocks)}\\\")\\n\\nprint(\\\"\\\\n=== 第二步：筛选半导体相关股票 ===\\\")\\nsemiconductor_keywords = ['半导体', '芯片', '微电子', '集成电路', '晶圆', '封测']\\nsemiconductor_stocks = []\\n\\nfor idx, row in gem_stocks.iterrows():\\n    stock_name = row['名称']\\n    if any(keyword in stock_name for keyword in semiconductor_keywords):\\n        semiconductor_stocks.append({\\n            'code': row['代码'],\\n            'name': stock_name\\n        })\\n\\nprint(f\\\"半导体相关股票数: {len(semiconductor_stocks)}\\\")\\nfor stock in semiconductor_stocks[:10]:\\n    print(f\\\"  {stock['code']} {stock['name']}\\\")\\n\\nprint(\\\"\\\\n=== 第三步：计算MACD并检测金叉 ===\\\")\\n\\ndef calculate_macd(df):\\n    \\\"\\\"\\\"计算MACD指标\\\"\\\"\\\"\\n    df['ema12'] = df['收盘'].ewm(span=12, adjust=False).mean()\\n    df['ema26'] = df['收盘'].ewm(span=26, adjust=False).mean()\\n    df['diff'] = df['ema12'] - df['ema26']\\n    df['dea'] = df['diff'].ewm(span=9, adjust=False).mean()\\n    df['macd'] = (df['diff'] - df['dea']) * 2\\n    return df\\n\\ndef detect_golden_cross(df, target_date='2024-03-15', recent_days=5):\\n    \\\"\\\"\\\"检测MACD金叉\\\"\\\"\\\"\\n    df = df.sort_values('日期')\\n    df = df[df['日期'] <= target_date].tail(30)  # 取目标日期前30天\\n    \\n    if len(df) < 20:\\n        return None, None\\n    \\n    df = calculate_macd(df)\\n    \\n    # 检查最近5个交易日内的金叉\\n    last_5_days = df.tail(5)\\n    \\n    for i in range(1, len(last_5_days)):\\n        prev_idx = last_5_days.index[i-1]\\n        curr_idx = last_5_days.index[i]\\n        \\n        prev_diff = df.loc[prev_idx, 'diff']\\n        prev_dea = df.loc[prev_idx, 'dea']\\n        curr_diff = df.loc[curr_idx, 'diff']\\n        curr_dea = df.loc[curr_idx, 'dea']\\n        \\n        # 金叉：DIFF从下